  const match = original.match(/^(https?):\/\/([^\/?#\s]+)([^\s]*)?$/i);
  if (!match) {
    return { ok: false, error: '?? URL ??????? http/https?' };
  }

  const protocol = match[1].toLowerCase();
  const authority = match[2];
  let rest = match[3] || '/';
  let hostname = authority.replace(/:\d+$/, '').toLowerCase();

  if (!hostname || hostname.includes('@') || hostname.includes('..')) {
    return { ok: false, error: '?? URL ???? hostname?' };
  }

  if (!/^[a-z0-9.-]+$/.test(hostname) || hostname.indexOf('.') === -1) {
    return { ok: false, error: '?? hostname ?????' };
