  }

  rest = rest.split('#')[0] || '/';
  if (!rest.startsWith('/')) rest = '/' + rest;

  const rootDomain = hostname.replace(/^www\./, '');
  return {
    ok: true,
    normalized: protocol + '://' + authority.toLowerCase() + rest,
    hostname,
    rootDomain,
